// === File I/O (node-only) =================================================
// In a browser context these all panic with a friendly message; the
// playground can override _omg_fs with a virtual FS if it wants
// programs that touch files to work.

let _omg_fs = null;
if (typeof require !== 'undefined') {
    try { _omg_fs = require('fs'); } catch (_e) { _omg_fs = null; }
}

function _need_fs(name) {
    if (!_omg_fs) {
        omg_panic('TypeError', name + '() requires file I/O (node-only)');
    }
}

function omg_read_file(path) {
    _need_fs('read_file');
    try {
        return _omg_fs.readFileSync(path, 'utf8');
    } catch (_e) {
        return false;
    }
}

function omg_file_exists(path) {
    _need_fs('file_exists');
    return _omg_fs.existsSync(path);
}

function omg_is_dir(path) {
    _need_fs('is_dir');
    try { return _omg_fs.statSync(path).isDirectory(); } catch (_e) { return false; }
}

function omg_read_dir(path) {
    _need_fs('read_dir');
    try {
        return _omg_fs.readdirSync(path).sort().filter(n => n !== '.' && n !== '..');
    } catch (_e) {
        return [];
    }
}

function omg_make_dir(path) {
    _need_fs('make_dir');
    try { _omg_fs.mkdirSync(path, { recursive: true }); return true; }
    catch (_e) { return false; }
}

// File handles for stream I/O. We implement a tiny in-memory buffer
// model (read whole file at open, write to a buffer flushed at close).
// Mode is one of r/rb/w/wb/a/ab/rb+/wb+ — matches omg_rt.h.
const _omg_handles = new Map();
let _omg_next_fd = 1;

function omg_file_open(path, mode) {
    _need_fs('file_open');
    if (typeof path !== 'string' || typeof mode !== 'string') {
        omg_panic('TypeError', 'file_open() expects path and mode');
    }
    const binary = mode.includes('b');
    const fd = _omg_next_fd++;
    let buf;
    if (mode === 'r' || mode === 'rb' || mode === 'rb+') {
        try {
            buf = _omg_fs.readFileSync(path);
        } catch (_e) {
            omg_panic('ValueError', "cannot open '" + path + "': " + _e.message);
        }
    } else if (mode === 'w' || mode === 'wb' || mode === 'wb+') {
        // Eagerly create (and truncate) the file so a bad path fails
        // at file_open time, matching Rust's fopen(path, "w") which
        // also fails immediately if the parent directory doesn't
        // exist. Subsequent file_close will overwrite this empty
        // initial content with whatever was actually written.
        try {
            _omg_fs.writeFileSync(path, '');
        } catch (_e) {
            omg_panic('ValueError', "cannot open '" + path + "': " + _e.message);
        }
        buf = Buffer.alloc(0);
    } else if (mode === 'a' || mode === 'ab') {
        // Eagerly create (without truncating) so a bad path fails at
        // file_open time, matching Rust's fopen(path, "a"). If the
        // file already exists, this is a no-op append of zero bytes.
        try {
            _omg_fs.writeFileSync(path, '', { flag: 'a' });
        } catch (_e) {
            omg_panic('ValueError', "cannot open '" + path + "': " + _e.message);
        }
        try { buf = _omg_fs.readFileSync(path); } catch (_e) { buf = Buffer.alloc(0); }
    } else {
        omg_panic('ValueError', 'invalid file mode');
    }
    _omg_handles.set(fd, { path, mode, binary, buf, pos: (mode === 'a' || mode === 'ab') ? buf.length : 0 });
    return BigInt(fd);
}

function omg_file_read(handle) {
    const h = _omg_handles.get(Number(omg_as_int(handle)));
    if (!h) omg_panic('ValueError', 'invalid file handle');
    const slice = h.buf.subarray(h.pos);
    h.pos = h.buf.length;
    if (h.binary) return Array.from(slice).map(b => BigInt(b));
    return slice.toString('utf8');
}

function omg_file_write(handle, data) {
    const h = _omg_handles.get(Number(omg_as_int(handle)));
    if (!h) omg_panic('ValueError', 'invalid file handle');
    let chunk;
    if (h.binary) {
        if (!Array.isArray(data)) omg_panic('TypeError', 'file_write() binary handle expects list');
        chunk = Buffer.from(data.map(v => Number(omg_as_int(v))));
    } else {
        if (typeof data !== 'string') omg_panic('TypeError', 'file_write() text handle expects string');
        chunk = Buffer.from(data, 'utf8');
    }
    if (h.pos < h.buf.length) {
        // Overwrite in place, growing if needed.
        const need = h.pos + chunk.length;
        if (need > h.buf.length) {
            const nb = Buffer.alloc(need);
            h.buf.copy(nb, 0, 0, h.buf.length);
            h.buf = nb;
        }
        chunk.copy(h.buf, h.pos);
    } else {
        h.buf = Buffer.concat([h.buf, chunk]);
    }
    h.pos += chunk.length;
    return BigInt(chunk.length);
}

function omg_file_close(handle) {
    const fd = Number(omg_as_int(handle));
    const h = _omg_handles.get(fd);
    if (!h) omg_panic('ValueError', 'invalid file handle');
    if (h.mode !== 'r' && h.mode !== 'rb') {
        try { _omg_fs.writeFileSync(h.path, h.buf); }
        catch (_e) { omg_panic('ValueError', 'cannot write ' + h.path + ': ' + _e.message); }
    }
    _omg_handles.delete(fd);
    return null;
}

function omg_file_seek(handle, offset) {
    const h = _omg_handles.get(Number(omg_as_int(handle)));
    if (!h) omg_panic('ValueError', 'invalid file handle');
    const off = Number(omg_as_int(offset));
    if (off < 0) omg_panic('ValueError', 'file_seek() expects a non-negative offset');
    h.pos = off;
    return BigInt(off);
}

function omg_file_tell(handle) {
    const h = _omg_handles.get(Number(omg_as_int(handle)));
    if (!h) omg_panic('ValueError', 'invalid file handle');
    return BigInt(h.pos);
}

// === Stdin / process control (node-only) =================================

function omg_stdin_readline() {
    if (typeof require === 'undefined') return false;
    // Synchronous one-line stdin read via fs.readFileSync('/dev/stdin').
    // Cached on first call so subsequent calls walk lines from the cache.
    if (!omg_stdin_readline._buf) {
        try {
            omg_stdin_readline._buf = _omg_fs.readFileSync(0, 'utf8');
            omg_stdin_readline._pos = 0;
        } catch (_e) {
            omg_stdin_readline._buf = '';
            omg_stdin_readline._pos = 0;
        }
    }
    const buf = omg_stdin_readline._buf;
    let pos = omg_stdin_readline._pos;
    if (pos >= buf.length) return false;
    const nl = buf.indexOf('\n', pos);
    let line;
    if (nl < 0) { line = buf.slice(pos); omg_stdin_readline._pos = buf.length; }
    else { line = buf.slice(pos, nl); omg_stdin_readline._pos = nl + 1; }
    if (line.endsWith('\r')) line = line.slice(0, -1);
    return line;
}

function omg_stdin_read() {
    if (typeof require === 'undefined') return '';
    try { return _omg_fs.readFileSync(0, 'utf8'); }
    catch (_e) { return ''; }
}

function omg_stdin_read_bytes() {
    if (typeof require === 'undefined') return [];
    try { return Array.from(_omg_fs.readFileSync(0)).map(b => BigInt(b)); }
    catch (_e) { return []; }
}

function omg_subprocess(argv) {
    if (typeof require === 'undefined') {
        omg_panic('TypeError', 'subprocess() requires node');
    }
    const { spawnSync } = require('child_process');
    if (!Array.isArray(argv)) omg_panic('TypeError', 'subprocess() expects a list');
    const cmd = argv[0];
    const args = argv.slice(1);
    const r = spawnSync(cmd, args, { stdio: 'inherit' });
    if (r.error) omg_panic('ValueError', 'subprocess: ' + r.error.message);
    return BigInt(r.status === null ? 128 + (r.signal === 'SIGINT' ? 2 : 1) : r.status);
}

function omg_getpid() {
    return BigInt(typeof process !== 'undefined' ? process.pid : 0);
}

function omg_executable_path() {
    return typeof process !== 'undefined' ? process.argv[0] : false;
}

